import { DEFAULT_CHIRPIER_EVENT_CHART_STATE as DEFAULT_CHIRPIER_EVENT_CHART_STATE_VALUE, DEFAULT_CHIRPIER_EVENT_TRACKER_RULE as DEFAULT_CHIRPIER_EVENT_TRACKER_RULE_VALUE, } from "@chirpier/embed";
export const DEFAULT_CHIRPIER_EVENT_CHART_STATE = DEFAULT_CHIRPIER_EVENT_CHART_STATE_VALUE;
export const DEFAULT_CHIRPIER_EVENT_TRACKER_RULE = DEFAULT_CHIRPIER_EVENT_TRACKER_RULE_VALUE;
export function createChirpierChartState(input = {}) {
    return {
        ...DEFAULT_CHIRPIER_EVENT_CHART_STATE_VALUE,
        ...input,
        tracker: {
            ...DEFAULT_CHIRPIER_EVENT_TRACKER_RULE_VALUE,
            ...input.tracker,
        },
    };
}
